+    }
+}
+
+#[test]
+fn expression_numeric_literal_i64_min() {
+    let expr = Expression::NumericLiteral(i64::MIN);
+    if let Expression::NumericLiteral(val) = &expr {
+        assert_eq!(*val, i64::MIN);
+    } else {
+        panic!("expected NumericLiteral");
+    }
