+fn parse_goal(raw: &str) -> ParseGoal {
+    match raw {
+        "script" => ParseGoal::Script,
+        "module" => ParseGoal::Module,
+        other => panic!("unknown goal in fixture catalog: {other}"),
+    }
+}
