+    }
+
+    let matrix_ids: BTreeSet<&str> = matrix_by_family.keys().copied().collect();
+    let mut backlog_ids: BTreeSet<&str> = BTreeSet::new();
+
+    for family in &backlog.families {
+        assert!(
+            backlog_ids.insert(family.family_id.as_str()),
