+fn make_scenario(fault_type: FaultType, expect_quarantine: bool) -> FaultScenario {
+    FaultScenario {
+        scenario_id: "test-scenario".to_string(),
+        fault_type,
+        target_extension: "ext-test-001".to_string(),
+        detection_latency_ns: 100_000_000,
